There are some missing vnet restore in net/if_ethersubr.c that can cause
networking code to execute in the wrong vnet context.

A patch is provided here:

[pc20 /u/vijay/bsd/CODE/9s/sys]# svn diff net/if_ethersubr.c
Index: net/if_ethersubr.c
===================================================================
--- net/if_ethersubr.c  (revision 232242)
+++ net/if_ethersubr.c  (working copy)
@@ -661,8 +661,10 @@
              m = (*lagg_input_p)(ifp, m);
              if (m != NULL)
                      ifp = m->m_pkthdr.rcvif;
-               else
+               else {
+                       CURVNET_RESTORE();
                      return;
+               }
      }

      /*
@@ -681,6 +683,7 @@
 #endif
                      ifp->if_ierrors++;
                      m_freem(m);
+                       CURVNET_RESTORE();
                      return;
              }

Fix: [pc20 /u/vijay/bsd/CODE/9s/sys]# svn diff net/if_ethersubr.c


/*
@@ -681,6 +683,7 @@
 #endif
                      ifp->if_ierrors++;
                      m_freem(m);
+                       CURVNET_RESTORE();
                      return;
              }--XEZIeGUpT7aj9QNaoVP2uE2m5BfSKRCrVj64dzZ6Ad70yrZ0
